import { useState } from 'react';

const styles = {
  nav: {
    position: 'sticky', top: 0, zIndex: 100,
    background: 'rgba(253,246,248,0.92)',
    backdropFilter: 'blur(16px)',
    borderBottom: '1px solid var(--border)',
    padding: '0 32px',
  },
  inner: {
    maxWidth: 1100, margin: '0 auto',
    display: 'flex', alignItems: 'center',
    justifyContent: 'space-between', height: 64,
  },
  logo: {
    display: 'flex', alignItems: 'center', gap: 10, cursor: 'pointer',
  },
  logoIcon: {
    width: 36, height: 36, borderRadius: '50%',
    background: 'linear-gradient(135deg, var(--rose) 0%, var(--rose-dark) 100%)',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    fontSize: 18,
  },
  logoText: {
    fontFamily: 'var(--font-display)',
    fontSize: 20, fontWeight: 600, color: 'var(--slate)',
    letterSpacing: '-0.3px',
  },
  logoSub: {
    fontSize: 10, color: 'var(--rose)', fontWeight: 600,
    letterSpacing: '0.08em', textTransform: 'uppercase',
    display: 'block', marginTop: -2,
  },
  links: { display: 'flex', gap: 4 },
  link: (active) => ({
    padding: '7px 16px', borderRadius: 99,
    fontSize: 14, fontWeight: 500, cursor: 'pointer',
    border: 'none', background: active ? 'var(--rose)' : 'transparent',
    color: active ? '#fff' : 'var(--slate-mid)',
    transition: 'all 0.2s ease',
    letterSpacing: '0.01em',
  }),
  badge: {
    display: 'inline-block',
    background: 'var(--rose-light)', color: 'var(--rose-dark)',
    fontSize: 10, fontWeight: 600, padding: '2px 8px',
    borderRadius: 99, letterSpacing: '0.06em', textTransform: 'uppercase',
    border: '1px solid var(--rose-mid)',
  }
};

export default function Navbar({ currentPage, onNavigate }) {
  const links = [
    { id: 'predict',   label: 'Predict' },
    { id: 'dashboard', label: 'Dashboard' },
    { id: 'about',     label: 'About' },
  ];

  return (
    <nav style={styles.nav}>
      <div style={styles.inner}>
        <div style={styles.logo} onClick={() => onNavigate('predict')}>
          <div style={styles.logoIcon}>🌸</div>
          <div>
            <span style={styles.logoText}>BabyBloom</span>
            <span style={styles.logoSub}>AI · Health Risk System</span>
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
          <span style={styles.badge}>ML Powered</span>
          <div style={styles.links}>
            {links.map(l => (
              <button
                key={l.id}
                style={styles.link(currentPage === l.id)}
                onClick={() => onNavigate(l.id)}
                onMouseEnter={e => {
                  if (currentPage !== l.id)
                    e.target.style.background = 'var(--rose-light)';
                }}
                onMouseLeave={e => {
                  if (currentPage !== l.id)
                    e.target.style.background = 'transparent';
                }}
              >
                {l.label}
              </button>
            ))}
          </div>
        </div>
      </div>
    </nav>
  );
}
